const state=loadState(), registry=loadReg(); let scanTimer=null,lastScan={at:'',packs:0,maint:0,content:{},textLength:0};
const host=document.createElement('div'); host.id='dcf-chatgpt-microcore-host'; const root=host.attachShadow({mode:'open'}); root.innerHTML=`<style>
:host{all:initial}.shell{position:fixed;top:72px;right:12px;bottom:86px;width:var(--w,min(356px,calc(100vw - 28px)));z-index:2147483646;display:flex;flex-direction:column;border:1px solid #9996;border-radius:16px;background:#fffffff0;color:#111;box-shadow:0 18px 44px #0002;font:13px/1.42 system-ui,-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;overflow:hidden}.shell[data-side=left]{left:12px;right:auto}@media(prefers-color-scheme:dark){.shell{background:#171717ee;color:#f5f5f5;border-color:#fff3;box-shadow:0 18px 44px #0008}}.top{display:flex;justify-content:space-between;gap:10px;padding:10px;border-bottom:1px solid #9994}.title{font-weight:780}.sub,.mini{font-size:11px;opacity:.62}.pill{border:1px solid #2563eb66;border-radius:999px;padding:3px 7px;font-size:11px}.tabs{display:grid;grid-template-columns:1fr 1fr;gap:6px;padding:8px 10px;border-bottom:1px solid #9993}.tab,.a,.railbtn,.modpick{border:1px solid #9995;border-radius:10px;background:transparent;color:inherit;cursor:pointer}.tab{padding:7px 0;font-weight:650}.tab[aria-selected=true],.a.primary,.railbtn[aria-selected=true],.modpick[aria-selected=true]{background:#2563eb22;border-color:#2563eb66;font-weight:700}.main{flex:1;min-height:0;display:flex}.rail{width:var(--rw,34px);flex:0 0 var(--rw,34px);border-right:1px solid #9993;padding:7px 4px;display:flex;flex-direction:column;gap:6px;background:#8881}.railbtn{width:100%;min-height:58px;padding:6px 2px;writing-mode:vertical-rl;text-orientation:mixed;letter-spacing:.12em;font:12px/1 system-ui}.content{flex:1;min-width:0;overflow:auto;padding:var(--sp,9px)}.notice{border:1px solid #05966955;background:#05966918;border-radius:12px;padding:8px 9px;margin-bottom:10px}.block{border:1px solid #9994;border-radius:var(--rad,14px);margin-bottom:10px;overflow:hidden;background:#8881}.head{width:100%;display:flex;justify-content:space-between;gap:10px;border:0;padding:10px 12px;color:inherit;background:transparent;text-align:left;cursor:pointer;font:inherit}.bt{font-weight:760}.bd{font-size:12px;opacity:.62}.body{padding:0 10px 10px;border-top:1px solid #9992}.card{border:1px solid #9993;border-radius:12px;padding:9px;margin-top:8px}.name{font-weight:720}.desc{font-size:12px;opacity:.68;margin-top:3px}.actions{display:flex;flex-wrap:wrap;gap:7px;margin-top:10px}.a{padding:7px 9px;font:12px/1.1 system-ui}.a.hot{background:#7c3aed22;border-color:#7c3aed66;font-weight:700}.a.warnbtn{background:#d9770622;border-color:#d9770666}.empty{border:1px dashed #9996;border-radius:12px;padding:12px;opacity:.72}.chips{display:flex;flex-wrap:wrap;gap:5px;margin-top:7px}.chip{border:1px solid #9994;border-radius:999px;padding:2px 6px;font-size:11px;opacity:.76}.kv{font:11px/1.35 ui-monospace,SFMono-Regular,Menlo,Consolas,monospace;word-break:break-all;opacity:.72}.seg{display:flex;gap:6px;margin:10px 0 0}.seg .a{padding:6px 8px}.seg .a[aria-selected=true]{background:#2563eb22;border-color:#2563eb66}.moduleshell{display:flex;border:1px solid #9994;border-radius:14px;overflow:hidden;background:#8881}.modulelist{width:var(--mrw,38px);flex:0 0 var(--mrw,38px);border-right:1px solid #9993;padding:7px 4px;display:flex;flex-direction:column;gap:6px;overflow:auto;background:#8881}.modpick{width:100%;min-height:82px;padding:7px 2px;writing-mode:vertical-rl;text-orientation:mixed;letter-spacing:.06em;font:12px/1.05 system-ui}.modulepane{flex:1;min-width:0;overflow:auto;padding:0 10px 10px}.modulemain{display:flex;gap:8px;margin-top:10px}.modrail{width:32px;flex:0 0 32px;display:flex;flex-direction:column;gap:6px}.modrail .a{width:100%;min-height:48px;padding:6px 2px;writing-mode:vertical-rl;text-orientation:mixed}.modulebody{flex:1;min-width:0}.split{display:flex;gap:8px}.split>*{flex:1;min-width:0}.text{white-space:pre-wrap}.field{margin-top:8px}.field label{display:block;font-size:12px;opacity:.72;margin-bottom:3px}.field input,.field select,textarea{width:100%;box-sizing:border-box;border:1px solid #9995;border-radius:10px;padding:7px;background:#fff8;color:inherit}textarea{min-height:92px;font:12px/1.45 ui-monospace,SFMono-Regular,Menlo,Consolas,monospace}@media(prefers-color-scheme:dark){textarea,.field input,.field select{background:#0003}}
</style><aside class='shell'></aside>`; const shell=root.querySelector('.shell'); document.documentElement.appendChild(host);
shell.addEventListener('click',onClick); shell.addEventListener('input',onInput); registerMenu(); render(); scheduleScan(220); new MutationObserver(()=>scheduleScan(750)).observe(document.body,{childList:true,subtree:true,characterData:true});
function render(){applyPolicy(); const p=ui(); const content=`${state.notice?`<div class='notice'>${esc(state.notice)}</div>`:''}${state.tab==='modules'?modulesView():maintView()}`; shell.dataset.side=state.side; if(p.nav_style==='side_tabs') shell.innerHTML=`<div class='top'><div><div class='title'>DCF Kernel</div><div class='sub'>native ${VERSION} · hot-update baseline</div></div><span class='pill'>${registry.modules.length} modules</span></div><div class='main'><nav class='rail'>${rail('maint','维护')}${rail('modules','模块')}</nav><div class='content'>${content}</div></div>`; else shell.innerHTML=`<div class='top'><div><div class='title'>DCF Kernel</div><div class='sub'>native ${VERSION} · hot-update baseline</div></div><span class='pill'>${registry.modules.length} modules</span></div><div class='tabs'>${tab('maint','维护')}${tab('modules','模块')}</div><div class='content'>${content}</div>`}
function rail(t,l){return `<button class='railbtn' aria-selected='${state.tab===t}' data-act='tab' data-tab='${t}' title='${esc(l)}'>${esc(l)}</button>`} function tab(t,l){return `<button class='tab' aria-selected='${state.tab===t}' data-act='tab' data-tab='${t}'>${esc(l)}</button>`}
function applyPolicy(){const p=ui(),s=registry.styleTokens||{}; shell.style.setProperty('--w',css(s.panel_width_css||p.panel_width_css,DEFAULT_UI.panel_width_css)); shell.style.setProperty('--rw',css(s.rail_width_css||p.rail_width_css,DEFAULT_UI.rail_width_css)); shell.style.setProperty('--mrw',css(s.module_rail_width_css||p.module_rail_width_css,DEFAULT_UI.module_rail_width_css)); shell.style.setProperty('--sp',css(s.spacing||'9px','9px')); shell.style.setProperty('--rad',css(s.radius||'14px','14px'))}
function maintView(){return `${section('status','内核状态','热更新底座、扫描、策略。',statusBody())}${section('install','模块包入口','支持 contributes、ui_policy、views、content、settings、styles。',installBody())}${section('events','轻量日志','最近 60 条本地事件。',eventsBody())}${section('caps','能力接口','模块可申请和调用的能力面。',capsBody())}${section('repair','维护请求','不依赖普通模块命令的日志回传。',repairBody())}${section('danger','恢复','本地状态清理。',dangerBody())}`}
function modulesView(){const views=Object.values(registry.uiViews).sort((a,b)=>(a.order||50)-(b.order||50)).map(renderView).join(''); const mods=visibleModules(); if(!mods.length)return `${views}<div class='empty'>当前没有可显示模块。</div>`; const style=(nav().style||ui().module_list_style); if(style==='side_tabs')return `${views}${renderModuleRail(mods)}`; if(style==='top_tabs')return `${views}${renderModuleTop(mods)}`; if(style==='compact_list')return `${views}${mods.map(m=>`<div class='card'><div class='name'>${esc(titleOf(m))}</div><div class='actions'><button class='a primary' data-act='select-module' data-module='${esc(m.id)}'>打开</button></div></div>`).join('')}`; return `${views}${mods.map(renderModuleCard).join('')}`}
function renderModuleRail(mods){const m=selectedModule(mods);return `<div class='moduleshell'><nav class='modulelist'>${mods.map(x=>`<button class='modpick' aria-selected='${m&&m.id===x.id}' data-act='select-module' data-module='${esc(x.id)}' title='${esc(titleOf(x))}'>${esc(short(titleOf(x)))}</button>`).join('')}</nav><div class='modulepane'>${m?renderSelectedModule(m):'<div class="empty">请选择模块。</div>'}</div></div>`}
function renderModuleTop(mods){const m=selectedModule(mods);return `<div class='seg'>${mods.map(x=>`<button class='a' aria-selected='${m&&m.id===x.id}' data-act='select-module' data-module='${esc(x.id)}'>${esc(titleOf(x))}</button>`).join('')}</div>${m?renderSelectedModule(m):''}`}
function selectedModule(mods){let m=mods.find(x=>x.id===state.selectedModuleId)||mods[0]; if(m&&state.selectedModuleId!==m.id){state.selectedModuleId=m.id;saveState()} return m||null} function short(t){t=String(t||'');return t.length>8?t.slice(0,8):t} function titleOf(m){return moduleDisplay(m.id).title||m.title}
function renderSelectedModule(m){const mt=state.moduleTabs[m.id]||'actions'; return `<section class='block'><button class='head' data-act='noop'><span><div class='bt'>${esc(titleOf(m))}</div>${m.description?`<div class='bd'>${esc(m.description)}</div>`:''}</span></button><div class='body'>${modulePanel(m,mt)}</div></section>`}
function renderModuleCard(m){const d=moduleDisplay(m.id),open=isOpen(m,d);const mt=state.moduleTabs[m.id]||'actions';return `<section class='block'><button class='head' data-act='toggle-module' data-module='${esc(m.id)}'><span><div class='bt'>${esc(d.title||m.title)}</div>${open&&m.description?`<div class='bd'>${esc(m.description)}</div>`:''}</span><span>${open?'−':'+'}</span></button>${open?`<div class='body'>${modulePanel(m,mt)}</div>`:''}</section>`}
function isOpen(m,d){if(state.moduleOpen[m.id]!=null)return !!state.moduleOpen[m.id]; if(d.collapsed!=null)return !d.collapsed; return !ui().module_collapsed_default}
function modulePanel(m,mt){if(ui().module_tabs_style==='side_tabs')return `<div class='modulemain'><div class='modrail'>${mTab(m,'actions','功能')}${mTab(m,'details','详情')}${mTab(m,'config','配置')}</div><div class='modulebody'>${moduleTabBody(m,mt)}</div></div>`;return `<div class='seg'>${mTab(m,'actions','功能')}${mTab(m,'details','详情')}${mTab(m,'config','配置')}</div>${moduleTabBody(m,mt)}`}
function mTab(m,t,l){return `<button class='a' aria-selected='${(state.moduleTabs[m.id]||'actions')===t}' data-act='module-tab' data-module='${esc(m.id)}' data-tab='${t}'>${esc(l)}</button>`}
function moduleTabBody(m,t){if(t==='details')return `<div class='card'><div class='name'>${esc(m.title)}</div><div class='desc'>${esc(m.description||'')}</div><div class='kv'>id: ${esc(m.id)}<br>version: ${esc(m.version)}<br>permissions: ${esc(m.permissions.join(', ')||'none')}<br>commands: ${m.commands.length} · blocks: ${m.blocks.length}</div></div>`; if(t==='config')return renderConfig(m); const bs=blocksOf(m); return bs.length?bs.map((b,bi)=>renderBlock(m,b,bi)).join(''):`<div class='empty'>没有可执行命令。</div>`}
function renderConfig(m){const settings=Object.values(registry.contributions.settings).filter(s=>!s.scope||s.scope===m.id||s.module_id===m.id);return `<div class='card'><div class='name'>显示配置</div><div class='kv'>${esc(JSON.stringify(moduleDisplay(m.id),null,2))}</div><div class='actions'><button class='a' data-act='collapse-module' data-module='${esc(m.id)}'>折叠</button><button class='a warnbtn' data-act='hide-module' data-module='${esc(m.id)}'>隐藏</button></div></div><div class='card'><div class='name'>模块设置</div>${settings.length?settings.map(renderSetting).join(''):'<div class="mini">没有声明 settings schema。</div>'}</div>`}
function renderSetting(s){const v=registry.settings.hasOwnProperty(s.key)?registry.settings[s.key]:s.default; if(Array.isArray(s.enum))return `<div class='field'><label>${esc(s.title||s.key)}</label><select data-act='setting' data-setting='${esc(s.key)}'>${s.enum.map(x=>`<option value='${esc(x)}' ${String(x)===String(v)?'selected':''}>${esc(x)}</option>`).join('')}</select></div>`;return `<div class='field'><label>${esc(s.title||s.key)}</label><input data-act='setting' data-setting='${esc(s.key)}' value='${esc(v==null?'':v)}'></div>`}
function renderBlock(m,b,bi){const cs=b.commands||[];return `<div class='card'><div class='name'>${esc(b.title||b.id)}</div>${b.description?`<div class='desc'>${esc(b.description)}</div>`:''}${cs.length?`<div class='actions'>${cs.map((c,ci)=>`<button class='a ${c.primary?'primary':''}' data-act='run-command' data-module='${esc(m.id)}' data-block='${bi}' data-command='${ci}'>${esc(c.label||c.id)}</button>`).join('')}</div>`:'<div class="mini">没有命令。</div>'}</div>`}
function renderView(v){const open=state.viewOpen[v.id]!==false&&!v.collapsed;return `<section class='block'><button class='head' data-act='toggle-view' data-view='${esc(v.id)}'><span><div class='bt'>${esc(v.title)}</div>${open&&v.description?`<div class='bd'>${esc(v.description)}</div>`:''}</span><span>${open?'−':'+'}</span></button>${open?`<div class='body'>${renderViewBody(v)}</div>`:''}</section>`}
function renderViewBody(v){if(v.type==='ammo_library')return contentLibrary('ammo'); if(v.type==='content_library')return contentLibrary(v.content_type||v.contentType||v.config?.content_type||'ammo'); if(v.body||v.tree||v.children)return node(v.body||v.tree||{type:'container',children:v.children||[]},{}); return `<div class='empty'>未知视图类型：${esc(v.type)}</div>`}
function node(n,vars){if(n==null)return''; if(typeof n==='string')return`<div class='text'>${esc(interp(n,vars,null))}</div>`; if(Array.isArray(n))return n.map(x=>node(x,vars)).join(''); const type=String(n.type||'container'); if(type==='container')return`<div>${node(n.children||[],vars)}</div>`; if(type==='text'||type==='markdown')return`<div class='text'>${esc(interp(n.text||n.content||'',vars,null))}</div>`; if(type==='card')return`<div class='card'><div class='name'>${esc(n.title||'')}</div>${n.description?`<div class='desc'>${esc(n.description)}</div>`:''}${node(n.children||n.body||[],vars)}</div>`; if(type==='section')return section(n.id||hash(JSON.stringify(n)),n.title||'Section',n.description||'',node(n.children||n.body||[],vars)); if(type==='split')return`<div class='split'>${(n.children||[]).map(x=>`<div>${node(x,vars)}</div>`).join('')}</div>`; if(type==='content_library')return contentLibrary(n.content_type||n.contentType||'ammo'); if(type==='store_list')return`<div class='kv'>${esc(JSON.stringify(kvSnapshot(n.namespace||'global'),null,2))}</div>`; return`<div class='empty'>未知节点：${esc(type)}</div>`}
function contentLibrary(type){const items=listContent(type); if(!items.length)return`<div class='empty'>没有内容资产：${esc(type)}</div>`;return items.map(it=>`<div class='card'><div class='name'>${esc(it.title||it.id)}</div><div class='desc'>${esc(it.purpose||it.trigger||it.kind||'')}</div><div class='actions'><button class='a primary' data-act='fire-content' data-content-type='${esc(type)}' data-content-id='${esc(it.id)}'>发射</button><button class='a' data-act='copy-content' data-content-type='${esc(type)}' data-content-id='${esc(it.id)}'>复制</button></div></div>`).join('')}
function section(id,title,desc,body){const open=state.section===id;return `<section class='block'><button class='head' data-act='section' data-section='${esc(id)}'><span><div class='bt'>${esc(title)}</div><div class='bd'>${esc(desc)}</div></span><span>${open?'−':'+'}</span></button>${open?`<div class='body'>${body}</div>`:''}</section>`}
function statusBody(){return `<div class='mini'>kernel: ${VERSION}</div><div class='mini'>scan: ${esc(lastScan.at||'pending')} · packs ${lastScan.packs} · content ${esc(JSON.stringify(lastScan.content))}</div><div class='mini'>modules: ${registry.modules.length} · packs: ${Object.keys(registry.installedPacks).length} · content types: ${Object.keys(registry.contentTypes).length}</div><div class='mini'>ui: ${esc(ui().id)} · nav ${esc(ui().nav_style)} · module navigator ${esc(nav().style||ui().module_list_style)}</div><div class='actions'><button class='a primary' data-act='copy-diag'>复制诊断</button><button class='a' data-act='send-diag'>发送诊断反馈</button><button class='a' data-act='scan-now'>立即扫描</button><button class='a' data-act='side'>切换左右</button></div>`}
function installBody(){return `<div class='mini'>0.9.0 允许包贡献 commands / views / layouts / moduleNavigator / contentTypes / settings / menus / styles。</div><textarea data-role='pack' placeholder='paste dcf.module_pack.v1 JSON'></textarea><div class='actions'><button class='a primary' data-act='apply-pack'>手动应用</button><button class='a hot' data-act='probe'>安装基线自检包</button><button class='a' data-act='copy-sample'>复制样例包</button></div>`}
function eventsBody(){const ev=recent(12);return `${ev.length?ev.map(e=>`<div class='card'><div class='name'>${esc(e.type||e.event||'event')} · ${esc(e.status||'')}</div><div class='mini'>${esc(e.at||'')}</div><div class='kv'>${esc(JSON.stringify(e))}</div></div>`).join(''):'<div class="empty">暂无事件。</div>'}<div class='actions'><button class='a' data-act='copy-log'>复制日志</button><button class='a warnbtn' data-act='clear-log'>清空日志</button></div>`}
function capsBody(){const g={};for(const n of CAP){const k=n.split('.')[0];(g[k]??=[]).push(n)}return Object.keys(g).map(k=>`<div class='card'><div class='name'>${esc(k)}.*</div><div class='chips'>${g[k].map(x=>`<span class='chip'>${esc(x)}</span>`).join('')}</div></div>`).join('')}
function repairBody(){return `<div class='mini'>维护请求只回传诊断，不执行任意动作。</div><div class='actions'><button class='a primary' data-act='copy-maint-request'>复制维护请求块</button><button class='a' data-act='copy-repair'>复制纠错提示</button></div>`}
